<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    :root {
      color-scheme: light;
      font-family: Arial, sans-serif;
      background: #f4f6f8;
      color: #20252b;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      padding: 24px;
    }

    main {
      width: min(900px, 100%);
      margin: 0 auto;
    }

    h1, h2 {
      margin-top: 0;
    }

    .panel {
      background: #fff;
      border: 1px solid #d9dee4;
      border-radius: 8px;
      padding: 20px;
      margin-bottom: 18px;
      box-shadow: 0 2px 6px rgba(0, 0, 0, 0.04);
    }

    .form-grid,
    .filter-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
      gap: 14px;
      align-items: end;
    }

    label {
      display: flex;
      flex-direction: column;
      gap: 6px;
      font-weight: 600;
      font-size: 0.9rem;
    }

    input,
    select,
    button {
      font: inherit;
      min-height: 38px;
      border: 1px solid #b9c1ca;
      border-radius: 5px;
      padding: 7px 9px;
      background: #fff;
    }

    button {
      cursor: pointer;
      background: #1769aa;
      color: #fff;
      border-color: #1769aa;
      font-weight: 600;
    }

    button:hover {
      background: #12578d;
    }

    .error {
      min-height: 1.3em;
      color: #b42318;
      margin: 12px 0 0;
      font-weight: 600;
    }

    .summary {
      display: flex;
      flex-wrap: wrap;
      gap: 14px;
      align-items: center;
    }

    .total {
      font-size: 1.25rem;
      font-weight: 700;
      margin-right: 10px;
    }

    .category-summary {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
    }

    .cat-total {
      border: 1px solid #d9dee4;
      border-radius: 5px;
      padding: 7px 10px;
      background: #f8fafb;
    }

    .expense-list {
      display: flex;
      flex-direction: column;
      gap: 9px;
    }

    .expense {
      display: grid;
      grid-template-columns: 1fr 1fr 1fr auto;
      gap: 12px;
      align-items: center;
      padding: 12px;
      border: 1px solid #d9dee4;
      border-radius: 6px;
      background: #fff;
    }

    .expense-amount {
      font-weight: 700;
    }

    .expense-date,
    .expense-category {
      color: #4c5966;
    }

    .exp-del {
      min-height: 32px;
      padding: 5px 9px;
      background: #c62828;
      border-color: #c62828;
    }

    .exp-del:hover {
      background: #9e1f1f;
    }

    .empty {
      color: #59636e;
      padding: 12px 0;
    }

    @media (max-width: 600px) {
      body {
        padding: 12px;
      }

      .expense {
        grid-template-columns: 1fr 1fr auto;
      }

      .expense-date {
        grid-column: 1 / 3;
      }
    }
  </style>
</head>
<body>
  <main>
    <h1>Personal Expense Tracker</h1>

    <section class="panel">
      <h2>Add Expense</h2>
      <form id="expense-form">
        <div class="form-grid">
          <label>
            Amount
            <input id="amount" type="number" step="0.01" min="0" inputmode="decimal">
          </label>

          <label>
            Category
            <select id="category">
              <option value="groceries">groceries</option>
              <option value="transport">transport</option>
              <option value="bills">bills</option>
              <option value="fun">fun</option>
            </select>
          </label>

          <label>
            Date
            <input id="date" type="date">
          </label>

          <label>
            Note (optional)
            <input id="note" type="text" maxlength="200">
          </label>

          <button id="add-expense" type="submit">Add Expense</button>
        </div>
        <p id="form-error" class="error" role="alert"></p>
      </form>
    </section>

    <section class="panel">
      <h2>Filters</h2>
      <div class="filter-grid">
        <label>
          Category
          <select id="filter-category">
            <option value="all">all</option>
            <option value="groceries">groceries</option>
            <option value="transport">transport</option>
            <option value="bills">bills</option>
            <option value="fun">fun</option>
          </select>
        </label>

        <label>
          From
          <input id="filter-from" type="date">
        </label>

        <label>
          To
          <input id="filter-to" type="date">
        </label>
      </div>
    </section>

    <section class="panel">
      <div class="summary">
        <div class="total">Total: <span id="total">0.00</span></div>
        <div class="category-summary" id="category-summary">
          <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
          <span class="cat-total" data-cat="transport">transport: 0.00</span>
          <span class="cat-total" data-cat="bills">bills: 0.00</span>
          <span class="cat-total" data-cat="fun">fun: 0.00</span>
        </div>
      </div>
    </section>

    <section class="panel">
      <h2>Expenses</h2>
      <div id="expense-list" class="expense-list"></div>
      <div id="empty-message" class="empty">No expenses found.</div>
    </section>
  </main>

  <script>
    (function () {
      "use strict";

      const STORAGE_KEY = "personal-expense-tracker-expenses";
      const categories = ["groceries", "transport", "bills", "fun"];

      const form = document.getElementById("expense-form");
      const amountInput = document.getElementById("amount");
      const categoryInput = document.getElementById("category");
      const dateInput = document.getElementById("date");
      const noteInput = document.getElementById("note");
      const formError = document.getElementById("form-error");
      const list = document.getElementById("expense-list");
      const emptyMessage = document.getElementById("empty-message");
      const totalElement = document.getElementById("total");
      const filterCategory = document.getElementById("filter-category");
      const filterFrom = document.getElementById("filter-from");
      const filterTo = document.getElementById("filter-to");

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          return Array.isArray(saved) ? saved : [];
        } catch (error) {
          return [];
        }
      }

      function saveExpenses() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
      }

      function money(value) {
        return Number(value).toFixed(2);
      }

      function visibleExpenses() {
        const selectedCategory = filterCategory.value;
        const from = filterFrom.value;
        const to = filterTo.value;

        return expenses.filter(function (expense) {
          if (selectedCategory !== "all" && expense.category !== selectedCategory) {
            return false;
          }
          if (from && expense.date < from) {
            return false;
          }
          if (to && expense.date > to) {
            return false;
          }
          return true;
        });
      }

      function render() {
        const visible = visibleExpenses();

        visible.sort(function (a, b) {
          if (a.date !== b.date) {
            return b.date.localeCompare(a.date);
          }
          return (b.createdAt || 0) - (a.createdAt || 0);
        });

        list.innerHTML = "";

        visible.forEach(function (expense) {
          const row = document.createElement("div");
          row.className = "expense";
          row.dataset.id = expense.id;

          const amount = document.createElement("span");
          amount.className = "expense-amount";
          amount.textContent = money(expense.amount);

          const category = document.createElement("span");
          category.className = "expense-category";
          category.textContent = expense.category;

          const date = document.createElement("span");
          date.className = "expense-date";
          date.textContent = expense.date;

          const deleteButton = document.createElement("button");
          deleteButton.className = "exp-del";
          deleteButton.type = "button";
          deleteButton.textContent = "Delete";
          deleteButton.addEventListener("click", function () {
            expenses = expenses.filter(function (item) {
              return item.id !== expense.id;
            });
            saveExpenses();
            render();
          });

          row.append(amount, category, date, deleteButton);
          list.appendChild(row);
        });

        emptyMessage.style.display = visible.length ? "none" : "block";

        const total = visible.reduce(function (sum, expense) {
          return sum + Number(expense.amount);
        }, 0);
        totalElement.textContent = money(total);

        categories.forEach(function (categoryName) {
          const categoryTotal = visible
            .filter(function (expense) {
              return expense.category === categoryName;
            })
            .reduce(function (sum, expense) {
              return sum + Number(expense.amount);
            }, 0);

          const summaryElement = document.querySelector(
            '.cat-total[data-cat="' + categoryName + '"]'
          );
          if (summaryElement) {
            summaryElement.textContent = categoryName + ": " + money(categoryTotal);
          }
        });
      }

      form.addEventListener("submit", function (event) {
        event.preventDefault();
        formError.textContent = "";

        const rawAmount = amountInput.value.trim();
        const amount = Number(rawAmount);
        const date = dateInput.value;

        if (!rawAmount || !Number.isFinite(amount) || amount <= 0) {
          formError.textContent = "Enter an amount greater than zero.";
          return;
        }

        if (!date) {
          formError.textContent = "Please select a date.";
          return;
        }

        expenses.push({
          id: String(Date.now()) + "-" + String(Math.random()).slice(2),
          amount: amount,
          category: categoryInput.value,
          date: date,
          note: noteInput.value.trim(),
          createdAt: Date.now()
        });

        saveExpenses();
        formError.textContent = "";
        amountInput.value = "";
        noteInput.value = "";
        render();
      });

      [filterCategory, filterFrom, filterTo].forEach(function (control) {
        control.addEventListener("change", render);
        control.addEventListener("input", render);
      });

      render();
    })();
  </script>
</body>
</html>
